#include <iostream>
#include <string>
#include <string_view>

class Point2D
{
    int m_x{};
    int m_y{};

public:
    Point2D(int x, int y)
        : m_x{ x }, m_y{ y }
    {
    }

    int getX() const { return m_x; }
    int getY() const { return m_y; }
};

class Creature
{
    std::string m_name;
    Point2D m_location;

public:
    Creature(std::string_view name, const Point2D& location)
        : m_name{ name }, m_location{ location }
    {
    }

    std::string_view getName() const { return m_name; }
    const Point2D& getLocation() const { return m_location; }
};

int main()
{
    std::string name{};
    std::cin >> name;

    int x{};
    int y{};
    std::cin >> x >> y;

    Creature c{ name, Point2D{ x, y } };
    std::cout << c.getName() << " is at ("
              << c.getLocation().getX() << ", "
              << c.getLocation().getY() << ")\n";

    return 0;
}

